const cart = [
    { name: 'Laptop', price: 45000, quantity: 1, category: 'Electronics' },
    { name: 'Mouse', price: 800, quantity: 2, category: 'Electronics' },
    { name: 'Keyboard', price: 2500, quantity: 1, category: 'Electronics' },
    { name: 'Notebook', price: 50, quantity: 5, category: 'Stationery' },
    { name: 'Pen', price: 20, quantity: 10, category: 'Stationery' },
    { name: 'Monitor', price: 15000, quantity: 1, category: 'Electronics' },
    { name: 'Desk', price: 8000, quantity: 1, category: 'Furniture' },
    { name: 'Chair', price: 5000, quantity: 2, category: 'Furniture' }
];

console.log('Shopping Cart Analysis');
console.log('=' .repeat(60));

// 1. Filter Electronics items
const electronics = cart.filter(item => item.category === 'Electronics');
console.log('1. Electronics Items:', electronics);

// 2. Calculate subtotal for each item
const itemsWithSubtotal = cart.map(item => ({
    ...item,
    subtotal: item.price * item.quantity
}));
console.log('\n2. Items with Subtotal:', itemsWithSubtotal);

// 3. Calculate total cart value
const totalCartValue = itemsWithSubtotal.reduce((total, item) => total + item.subtotal, 0);
console.log('\n3. Total Cart Value: ₹' + totalCartValue.toLocaleString('en-IN'));

// 4. Find items costing more than ₹5000 (subtotal)
const expensiveItems = itemsWithSubtotal.filter(item => item.subtotal > 5000);
console.log('\n4. Items costing > ₹5000:');
console.table(expensiveItems.map(item => ({
    name: item.name,
    subtotal: '₹' + item.subtotal.toLocaleString('en-IN')
})));

// 5. Sort items by price descending
const sortedByPrice = [...cart].sort((a, b) => b.price - a.price);
console.log('\n5. Items sorted by price (descending):');
console.table(sortedByPrice.map(item => ({
    name: item.name,
    price: '₹' + item.price.toLocaleString('en-IN'),
    category: item.category
})));

// 6. Create summary array with name and total cost
const summary = cart.map(item => ({
    itemName: item.name,
    totalCost: item.price * item.quantity,
    category: item.category
}));
console.log('\n6. Summary (Item Name + Total Cost):');
console.table(summary);

// Additional Analysis

// Category-wise total
const categoryTotals = cart.reduce((acc, item) => {
    const subtotal = item.price * item.quantity;
    if(!acc[item.category]) {
        acc[item.category] = 0;
    }
    acc[item.category] += subtotal;
    return acc;
}, {});

console.log('\nCategory-wise Spending:');
Object.entries(categoryTotals).forEach(([category, total]) => {
    console.log(`${category}: ₹${total.toLocaleString('en-IN')}`);
});

// Most expensive single item
const mostExpensive = cart.reduce((max, item) => 
    item.price > max.price ? item : max, cart[0]);
console.log(`\nMost Expensive Single Item: ${mostExpensive.name} (₹${mostExpensive.price.toLocaleString('en-IN')})`);

// Items that have quantity > 1
const bulkItems = cart.filter(item => item.quantity > 1);
console.log('\nItems bought in bulk (quantity > 1):');
bulkItems.forEach(item => {
    console.log(`${item.name}: ${item.quantity} units`);
});

// Apply discount: 10% off on Electronics, 5% off on others
const discountedCart = cart.map(item => {
    const discount = item.category === 'Electronics' ? 0.10 : 0.05;
    const discountedPrice = item.price * (1 - discount);
    return {
        ...item,
        originalPrice: item.price,
        discountedPrice: discountedPrice,
        savings: item.price - discountedPrice
    };
});

console.log('\nAfter Discount Application:');
console.table(discountedCart.map(item => ({
    name: item.name,
    original: '₹' + item.originalPrice,
    discounted: '₹' + item.discountedPrice.toFixed(2),
    savings: '₹' + item.savings.toFixed(2)
})));
