```javascript
class EmployeeManagementSystem {
    constructor() {
        this.employees = [];
        this.nextId = 1;
    }

    // Add new employee
    addEmployee(name, department, salary, joiningDate, performanceScore) {
        const employee = {
            id: this.nextId++,
            name: name,
            department: department,
            salary: salary,
            joiningDate: new Date(joiningDate),
            performanceScore: performanceScore
        };
        this.employees.push(employee);
        console.log(`Employee ${name} added successfully with ID: ${employee.id}`);
        return employee;
    }

    // Remove employee by id
    removeEmployee(id) {
        const index = this.employees.findIndex(emp => emp.id === id);
        if(index !== -1) {
            const removed = this.employees.splice(index, 1)[0];
            console.log(`Employee ${removed.name} (ID: ${removed.id}) removed successfully`);
            return removed;
        }
        console.log(`Employee with ID ${id} not found`);
        return null;
    }

    // Update employee salary
    updateSalary(id, newSalary) {
        const employee = this.employees.find(emp => emp.id === id);
        if(employee) {
            const oldSalary = employee.salary;
            employee.salary = newSalary;
            console.log(`Salary updated for ${employee.name}: ₹${oldSalary} → ₹${newSalary}`);
            return true;
        }
        console.log(`Employee with ID ${id} not found`);
        return false;
    }

    // Find employees by department
    findEmployeesByDepartment(department) {
        const employees = this.employees.filter(emp => 
            emp.department.toLowerCase() === department.toLowerCase()
        );
        console.log(`\nEmployees in ${department} department:`);
        employees.forEach(emp => {
            console.log(`  ${emp.name} (ID: ${emp.id}) - Salary: ₹${emp.salary}`);
        });
        return employees;
    }

    // Get employees with performance score > 8
    getTopPerformers() {
        const topPerformers = this.employees.filter(emp => emp.performanceScore > 8);
        console.log(`\nTop Performers (Score > 8):`);
        topPerformers.forEach(emp => {
            console.log(`  ${emp.name} (${emp.department}) - Score: ${emp.performanceScore}`);
        });
        return topPerformers;
    }

    // Calculate average salary by department
    getAverageSalaryByDepartment() {
        const departments = [...new Set(this.employees.map(emp => emp.department))];
        const avgSalary = {};

        departments.forEach(dept => {
            const deptEmployees = this.employees.filter(emp => emp.department === dept);
            const totalSalary = deptEmployees.reduce((sum, emp) => sum + emp.salary, 0);
            avgSalary[dept] = totalSalary / deptEmployees.length;
        });

        console.log('\nAverage Salary by Department:');
        Object.entries(avgSalary).forEach(([dept, avg]) => {
            console.log(`  ${dept}: ₹${avg.toLocaleString('en-IN')}`);
        });

        return avgSalary;
    }

    // Get top 3 highest paid employees
    getTopPaidEmployees() {
        const topPaid = [...this.employees]
            .sort((a, b) => b.salary - a.salary)
            .slice(0, 3);

        console.log('\nTop 3 Highest Paid Employees:');
        topPaid.forEach((emp, index) => {
            console.log(`  ${index + 1}. ${emp.name} (${emp.department}) - ₹${emp.salary.toLocaleString('en-IN')}`);
        });

        return topPaid;
    }

    // Sort employees by joining date (newest first)
    getEmployeesByJoiningDate() {
        const sorted = [...this.employees].sort((a, b) => b.joiningDate - a.joiningDate);

        console.log('\nEmployees sorted by Joining Date (Newest First):');
        sorted.forEach(emp => {
            console.log(`  ${emp.name} - Joined: ${emp.joiningDate.toLocaleDateString()}`);
        });

        return sorted;
    }

    // Generate salary report
    generateSalaryReport() {
        const totalExpenditure = this.employees.reduce((sum, emp) => sum + emp.salary, 0);
        const avgSalary = totalExpenditure / this.employees.length;
        const minSalary = Math.min(...this.employees.map(emp => emp.salary));
        const maxSalary = Math.max(...this.employees.map(emp => emp.salary));

        console.log('\n' + '='.repeat(60));
        console.log('SALARY REPORT');
        console.log('='.repeat(60));
        console.log(`Total Employees: ${this.employees.length}`);
        console.log(`Total Salary Expenditure: ₹${totalExpenditure.toLocaleString('en-IN')}`);
        console.log(`Average Salary: ₹${avgSalary.toLocaleString('en-IN')}`);
        console.log(`Minimum Salary: ₹${minSalary.toLocaleString('en-IN')}`);
        console.log(`Maximum Salary: ₹${maxSalary.toLocaleString('en-IN')}`);
        console.log('='.repeat(60));

        return {
            totalEmployees: this.employees.length,
            totalExpenditure: totalExpenditure,
            averageSalary: avgSalary,
            minSalary: minSalary,
            maxSalary: maxSalary
        };
    }

    // Check if any employee in a department earns more than a threshold
    hasHighEarner(department, threshold) {
        const hasHighEarner = this.employees.some(emp => 
            emp.department === department && emp.salary > threshold
        );
        console.log(`\n${department} department has employees earning > ₹${threshold}: ${hasHighEarner}`);
        return hasHighEarner;
    }

    // Check if all employees have performance score above a threshold
    allPerformersAbove(threshold) {
        const allAbove = this.employees.every(emp => emp.performanceScore > threshold);
        console.log(`\nAll employees have performance score > ${threshold}: ${allAbove}`);
        return allAbove;
    }

    // Get employee summary
    getEmployeeSummary() {
        const summary = this.employees.map(emp => ({
            id: emp.id,
            name: emp.name,
            department: emp.department,
            annualSalary: emp.salary * 12,
            performanceStatus: emp.performanceScore >= 8 ? 'Excellent' : 
                               emp.performanceScore >= 6 ? 'Good' : 'Needs Improvement'
        }));

        console.log('\nEmployee Summary:');
        console.table(summary);
        return summary;
    }

    // Display all employees
    displayAllEmployees() {
        if(this.employees.length === 0) {
            console.log('No employees found');
            return;
        }

        console.log('\n' + '='.repeat(80));
        console.log('ALL EMPLOYEES');
        console.log('='.repeat(80));
        console.table(this.employees.map(emp => ({
            ID: emp.id,
            Name: emp.name,
            Department: emp.department,
            Salary: '₹' + emp.salary.toLocaleString('en-IN'),
            'Joining Date': emp.joiningDate.toLocaleDateString(),
            'Performance Score': emp.performanceScore
        })));
    }
}

// ========== DEMONSTRATION ==========

const ems = new EmployeeManagementSystem();

// Add employees
ems.addEmployee('Alice Johnson', 'IT', 75000, '2023-01-15', 9);
ems.addEmployee('Bob Smith', 'HR', 55000, '2022-11-20', 7);
ems.addEmployee('Charlie Brown', 'IT', 85000, '2023-03-10', 9);
ems.addEmployee('Diana Prince', 'Finance', 65000, '2022-08-05', 8);
ems.addEmployee('Ethan Hunt', 'IT', 95000, '2023-06-01', 10);
ems.addEmployee('Fiona Gallagher', 'HR', 50000, '2023-02-28', 6);
ems.addEmployee('George Clooney', 'Finance', 70000, '2022-12-12', 8);

// Display all employees
ems.displayAllEmployees();

// Find employees by department
ems.findEmployeesByDepartment('IT');

// Get top performers
ems.getTopPerformers();

// Calculate average salary by department
ems.getAverageSalaryByDepartment();

// Get top 3 highest paid
ems.getTopPaidEmployees();

// Sort by joining date
ems.getEmployeesByJoiningDate();

// Generate salary report
ems.generateSalaryReport();

// Update salary
ems.updateSalary(3, 92000);

// Remove employee
ems.removeEmployee(2);

// Check for high earners
ems.hasHighEarner('IT', 90000);
ems.hasHighEarner('HR', 60000);

// Check if all employees perform above threshold
ems.allPerformersAbove(5);

// Get employee summary
ems.getEmployeeSummary();

// Display updated employees
ems.displayAllEmployees();

// Additional analysis: Department-wise total expenditure
const deptExpenditure = ems.employees.reduce((acc, emp) => {
    acc[emp.department] = (acc[emp.department] || 0) + emp.salary;
    return acc;
}, {});

console.log('\nDepartment-wise Expenditure:');
Object.entries(deptExpenditure).forEach(([dept, total]) => {
    console.log(`  ${dept}: ₹${total.toLocaleString('en-IN')}`);
});

// Performance analysis
const performanceGroups = ems.employees.reduce((groups, emp) => {
    const category = emp.performanceScore >= 9 ? 'Star Performers' :
                     emp.performanceScore >= 7 ? 'Good Performers' :
                     'Needs Improvement';
    if(!groups[category]) groups[category] = [];
    groups[category].push(emp.name);
    return groups;
}, {});

console.log('\nPerformance Groups:');
Object.entries(performanceGroups).forEach(([group, employees]) => {
    console.log(`  ${group}: ${employees.join(', ')}`);
});
